import styled from '@emotion/styled';

export const Label = styled.span`
  display: inherit;
  justify-content: inherit;
  align-items: inherit;
  flex-direction: inherit;
  height: inherit;
  width: 100%;

  svg {
    height: 100%;
  }
`;
